return [{
  json: {
    customer_id: 'B2B-1023',
    company_name: 'Demo Manufacturing Co.',
    churn_probability: 0.82,
    risk_level: 'Critical',
    expected_revenue_loss: 173000,
    fastapi_event: 'churn_signal_detected',
    model_version: 'churnradar-xgb-tcn-ts-v1',
    prediction_time: new Date().toISOString(),
    raw_signal: {
      energy: 'decreasing',
      momentum: 'negative',
      acceleration: 'risk spike near final period'
    },
    tool1_result: {
      shap_top_features: [
        { feature: 'Inactive_Ratio', contribution: 0.31 },
        { feature: 'Revenue_per_Active_Sub', contribution: 0.26 },
        { feature: 'Momentum_30d', contribution: 0.22 }
      ],
      tensor_input_shape: 'Customer x 30 Days x 3 Features',
      tensor_interpretation: 'Energy 감소, Momentum 음수 전환, Acceleration 위험 구간 발생'
    }
  }
}];

return $input.all().map((item) => {
  const shapText = item.json.tool1_result.shap_top_features
    .map((feature) => `${feature.feature}: ${feature.contribution}`)
    .join(', ');

  return {
    json: {
      ...item.json,
      analyst_output: {
        diagnosis: `${item.json.customer_id}는 이탈 확률 ${(item.json.churn_probability * 100).toFixed(1)}%의 ${item.json.risk_level} 고객입니다. 주요 원인은 ${shapText}이며, 3D Tensor상 ${item.json.tool1_result.tensor_interpretation} 패턴이 확인됩니다.`,
        evidence_type: ['SHAP', '3D Tensor', 'Churn Probability'],
        next_agent_instruction: '방어 전략 수립 단계에서 What-if Simulation으로 최적 대응안을 비교하세요.'
      }
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    tool2_result: {
      baseline_probability: item.json.churn_probability,
      scenarios: [
        { action: '10% discount', expected_probability: 0.7, action_cost: 30000 },
        { action: 'direct account call', expected_probability: 0.73, action_cost: 10000 },
        { action: 'bundle retention offer', expected_probability: 0.66, action_cost: 45000 }
      ]
    }
  }
}));

return $input.all().map((item) => {
  const bestScenario = item.json.tool2_result.scenarios
    .slice()
    .sort((a, b) => a.expected_probability - b.expected_probability)[0];

  return {
    json: {
      ...item.json,
      selected_strategy: bestScenario,
      strategist_output: {
        recommendation: `${bestScenario.action} 전략을 우선 적용합니다. 예상 이탈 확률은 ${(bestScenario.expected_probability * 100).toFixed(1)}%까지 낮아질 수 있습니다.`,
        expected_cost: bestScenario.action_cost,
        reason: '이탈 확률 감소 폭이 가장 큰 대응안입니다.',
        next_agent_instruction: '영업 담당자가 바로 사용할 수 있는 Slack/Gmail 메시지와 상담 스크립트를 작성하세요.'
      }
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    tool3_result: {
      slack_channel: '#churn-alert-high',
      gmail_to: 'sales-team-a@example.com',
      gmail_cc: 'retention-manager@example.com',
      delivery_policy: 'Critical 고객은 Slack과 Gmail 모두 발송'
    }
  }
}));

return $input.all().map((item) => {
  const probability = (item.json.churn_probability * 100).toFixed(1);
  const loss = item.json.expected_revenue_loss.toLocaleString();

  return {
    json: {
      ...item.json,
      communicator_output: {
        slack_message: `[${item.json.risk_level}] ${item.json.company_name} 이탈 위험 ${probability}% 감지. 권장 전략: ${item.json.selected_strategy.action}`,
        gmail_subject: `[ChurnRadar] ${item.json.customer_id} 이탈 위험 대응 요청`,
        gmail_body: `고객 ${item.json.company_name}의 이탈 위험이 감지되었습니다. 예상 손실은 ${loss}원입니다.\n\n진단 근거: ${item.json.analyst_output.diagnosis}\n\n권장 전략: ${item.json.strategist_output.recommendation}`,
        sales_script: `안녕하세요. 최근 서비스 이용 패턴을 점검해보니 일부 사용량 변화가 확인되어 연락드렸습니다. 현재 조건에서 ${item.json.selected_strategy.action} 혜택을 제안드릴 수 있습니다.`
      },
      next_agent_instruction: '알림, 스크립트, 리포트가 모두 기록 가능한지 검계하세요.'
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    tool4_result: {
      google_sheet_name: 'churn_log',
      mlflow_experiment: 'churnradar_retention_feedback',
      log_required: true,
      feedback_key: `${item.json.customer_id}-${Date.now()}`
    }
  }
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    auditor_output: {
      audit_status: 'passed',
      checked_items: [
        'SHAP/3D Tensor diagnosis exists',
        'What-if retention strategy exists',
        'Slack/Gmail message exists',
        'Google Sheets/MLflow logging target exists'
      ],
      tracking_report_required: true
    }
  }
}));

return $input.all().map((item) => ({
  json: {
    output_type: 'Slack 긴급 알림',
    channel: item.json.tool3_result.slack_channel,
    text: item.json.communicator_output.slack_message,
    preview_only: true
  }
}));

return $input.all().map((item) => ({
  json: {
    output_type: '영업 대응 스크립트',
    customer_id: item.json.customer_id,
    company_name: item.json.company_name,
    script: item.json.communicator_output.sales_script,
    selected_strategy: item.json.selected_strategy
  }
}));

return $input.all().map((item) => ({
  json: {
    output_type: '성과 추적 리포트',
    customer_id: item.json.customer_id,
    churn_probability: item.json.churn_probability,
    risk_level: item.json.risk_level,
    expected_revenue_loss: item.json.expected_revenue_loss,
    selected_action: item.json.selected_strategy.action,
    action_cost: item.json.selected_strategy.action_cost,
    google_sheet_name: item.json.tool4_result.google_sheet_name,
    mlflow_experiment: item.json.tool4_result.mlflow_experiment,
    audit_status: item.json.auditor_output.audit_status,
    feedback_key: item.json.tool4_result.feedback_key
  }
}));

return $input.all().map((item) => ({
  json: {
    feedback_loop: true,
    target: 'FastAPI / retraining queue',
    payload: {
      customer_id: item.json.customer_id,
      churn_probability: item.json.churn_probability,
      risk_level: item.json.risk_level,
      selected_action: item.json.selected_action,
      action_cost: item.json.action_cost,
      feedback_key: item.json.feedback_key
    },
    note: 'n8n에서는 실제 순환 연결 대신 이 노드에서 FastAPI 또는 재학습 큐로 피드백 payload를 전달합니다.'
  }
}));
